const checkpoints = [];

const services = JSON.parse(localStorage.getItem('services') || '[]');
const quotes = JSON.parse(localStorage.getItem('quote_requests') || '[]');

// Find piling services suitable for residential screw piling with depth >= 8m
const qualifyingServices = services.filter(s => {
  if (!s || s.service_type !== 'piling') return false;
  if (!Array.isArray(s.project_types) || !s.project_types.includes('residential')) return false;
  if (s.pile_type !== 'screw_piles') return false;
  if (typeof s.max_recommended_depth_m !== 'number' || s.max_recommended_depth_m < 8) return false;
  return true;
});

// Service-based quotes that use one of the qualifying services, residential project type, postcode 3000
const qualifyingQuotes = quotes.filter(q => {
  if (!q || q.source_type !== 'service') return false;
  if (q.site_postcode !== '3000') return false;
  if (q.project_type !== 'residential') return false;
  const svc = qualifyingServices.find(s => s.id === q.related_service_id);
  return !!svc;
});

// From those, look for descriptions that reference an extension (rear / house extension etc.)
const extensionQuotes = qualifyingQuotes.filter(q => {
  const desc = (q.project_description || '').toLowerCase();
  return desc.includes('extension');
});

// CP1 (0.6): At least one service quote for a qualifying residential screw piling service at postcode 3000
checkpoints.push({ passed: qualifyingQuotes.length > 0, weight: 0.6 });

// CP2 (0.4): At least one such quote clearly references an extension in the description
checkpoints.push({ passed: extensionQuotes.length > 0, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const estimates = JSON.parse(localStorage.getItem('pile_estimates') || '[]');
const quotes = JSON.parse(localStorage.getItem('quote_requests') || '[]');

// Pile estimates for 30m x 20m, firm clay, light industrial / warehouse, cost <= 60000
const qualifyingEstimates = estimates.filter(e => {
  if (!e) return false;
  if (e.building_length_m !== 30) return false;
  if (e.building_width_m !== 20) return false;
  if (e.soil_type !== 'firm_clay') return false;
  if (e.building_use_type !== 'light_industrial_warehouse') return false;
  if (typeof e.estimated_total_cost !== 'number' || e.estimated_total_cost > 60000) return false;
  return true;
});

// Among those estimates, find ones that have a corresponding pile_estimator quote for industrial project in postcode 5000
const estimatesWithQuote = qualifyingEstimates.filter(e => {
  return quotes.some(q => {
    if (!q) return false;
    if (q.source_type !== 'pile_estimator') return false;
    if (q.related_pile_estimate_id !== e.id) return false;
    if (q.site_postcode !== '5000') return false;
    if (q.project_type !== 'industrial') return false;
    return true;
  });
});

// CP1 (0.4): User produced at least one qualifying pile estimate meeting the dimension/soil/cost requirements
checkpoints.push({ passed: qualifyingEstimates.length > 0, weight: 0.4 });

// CP2 (0.6): User submitted at least one industrial quote request for postcode 5000 based on such an estimate
checkpoints.push({ passed: estimatesWithQuote.length > 0, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const equipment = JSON.parse(localStorage.getItem('equipment') || '[]');
const bookings = JSON.parse(localStorage.getItem('hire_bookings') || '[]');
const items = JSON.parse(localStorage.getItem('hire_booking_items') || '[]');

// All piling rigs that meet rating and price constraints
const allQualifyingRigs = equipment.filter(eq => {
  if (!eq || eq.category !== 'piling_rigs') return false;
  if (eq.is_available === false) return false;
  if (typeof eq.average_rating !== 'number' || eq.average_rating < 4) return false;
  if (typeof eq.daily_rate !== 'number' || eq.daily_rate >= 1000) return false;
  return true;
});

let cheapestRigIds = [];
if (allQualifyingRigs.length > 0) {
  const minRate = Math.min(...allQualifyingRigs.map(r => r.daily_rate || 0));
  cheapestRigIds = allQualifyingRigs.filter(r => r.daily_rate === minRate).map(r => r.id);
}

// Submitted bookings for postcode 4000
const submittedBookings = bookings.filter(b => b && b.status === 'submitted' && b.site_postcode === '4000');

// Helper to get equipment object for an item
function getEquipmentForItem(it) {
  return equipment.find(e => e.id === it.equipment_id) || null;
}

// Bookings where user hired ANY qualifying piling rig (rating/price) for exactly 3 days
const bookingsWithQualifyingRig3Days = submittedBookings.filter(b => {
  const relatedItems = items.filter(it => it.booking_id === b.id);
  return relatedItems.some(it => {
    const eq = getEquipmentForItem(it);
    if (!eq) return false;
    const isQualRig = eq.category === 'piling_rigs' && eq.is_available !== false &&
      typeof eq.average_rating === 'number' && eq.average_rating >= 4 &&
      typeof eq.daily_rate === 'number' && eq.daily_rate < 1000;
    return isQualRig && it.hire_days === 3;
  });
});

// Among those, bookings where the 3-day rig is one of the cheapest qualifying rigs
const bookingsWithCheapestRig3Days = bookingsWithQualifyingRig3Days.filter(b => {
  const relatedItems = items.filter(it => it.booking_id === b.id);
  return relatedItems.some(it => cheapestRigIds.includes(it.equipment_id) && it.hire_days === 3);
});

// CP1 (0.4): User submitted a booking for postcode 4000 that hires a qualifying piling rig (rating ≥4, rate <1000) for exactly 3 days
checkpoints.push({ passed: bookingsWithQualifyingRig3Days.length > 0, weight: 0.4 });

// CP2 (0.6): That 3-day rig is the cheapest available among all qualifying piling rigs
checkpoints.push({ passed: bookingsWithCheapestRig3Days.length > 0, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const projects = JSON.parse(localStorage.getItem('projects') || '[]');
const shortlists = JSON.parse(localStorage.getItem('project_shortlists') || '[]');
const shortlistId = localStorage.getItem('current_project_shortlist_id') || '';

const shortlist = shortlists.find(s => s.id === shortlistId) || null;
let shortlistedQualifying = [];

if (shortlist && Array.isArray(shortlist.project_ids)) {
  const qualifyingProjects = projects.filter(p => {
    if (!p || p.project_type !== 'basement_excavation') return false;
    if (typeof p.completion_year !== 'number') return false;
    if (p.completion_year < 2020 || p.completion_year > 2023) return false;
    const region = p.location_region;
    if (region !== 'melbourne' && region !== 'vic_melbourne_region') return false;
    return true;
  });

  shortlistedQualifying = qualifyingProjects.filter(p => shortlist.project_ids.includes(p.id));
}

// CP1-3: Number of qualifying projects in shortlist (each only counts if project meets all criteria)
[1, 2, 3].forEach((n, idx) => {
  const weight = idx === 2 ? 0.34 : 0.33; // 0.33 + 0.33 + 0.34 = 1.0
  checkpoints.push({ passed: shortlistedQualifying.length >= n, weight });
});

return checkoints = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const certs = JSON.parse(localStorage.getItem('certifications') || '[]');
const enquiries = JSON.parse(localStorage.getItem('contact_enquiries') || '[]');

const isoCert = certs.find(c => c && c.code === 'ISO 45001' && c.is_active !== false) || null;

const qualifyingEnquiries = enquiries.filter(e => {
  if (!e) return false;
  if (e.enquiry_type !== 'safety_compliance') return false;
  if (!isoCert) return false;
  if (e.related_certification_code !== isoCert.code) return false;
  const msg = e.message || '';
  // Must mention the certification by its exact name
  return msg.indexOf(isoCert.name) !== -1;
});

// Single checkpoint (1.0): At least one safety_compliance enquiry that correctly references ISO 45001 by name and code
checkpoints.push({ passed: qualifyingEnquiries.length > 0, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const callbacks = JSON.parse(localStorage.getItem('callback_requests') || '[]');

function describesTenLotSubdivision(desc) {
  const d = (desc || '').toLowerCase();
  const has10 = d.includes('10-lot') || d.includes('10 lot') || d.includes('ten-lot') || d.includes('ten lot');
  const hasSubdivision = d.includes('subdivision');
  return has10 && hasSubdivision;
}

function isWithinMorning(windowStr) {
  if (!windowStr) return false;
  const s = String(windowStr);
  // Prefer parsing explicit times like 9:30, 10:00 etc.
  const regex = /(\d{1,2})\s*:\s*(\d{2})/g;
  let match;
  const hours = [];
  while ((match = regex.exec(s)) !== null) {
    const h = parseInt(match[1], 10);
    if (!isNaN(h)) hours.push(h);
  }
  if (hours.length > 0) {
    const minH = Math.min(...hours);
    const maxH = Math.max(...hours);
    return minH >= 9 && maxH <= 11;
  }
  // Fallback: textual AM window mentioning 9, 10 or 11 and not PM
  const lower = s.toLowerCase();
  if (!lower.includes('am') || lower.includes('pm')) return false;
  if (/(\b9\b|\b10\b|\b11\b)/.test(lower)) return true;
  return false;
}

const descCallbacks = callbacks.filter(c => c && describesTenLotSubdivision(c.project_description || ''));
const fullQualCallbacks = descCallbacks.filter(c => isWithinMorning(c.preferred_contact_time_window || ''));

// CP1 (0.5): Callback request clearly describes a 10-lot subdivision project
checkpoints.push({ passed: descCallbacks.length > 0, weight: 0.5 });

// CP2 (0.5): Among those, at least one has a preferred contact window constrained between 9:00 and 11:00 AM
checkpoints.push({ passed: fullQualCallbacks.length > 0, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const branches = JSON.parse(localStorage.getItem('branches') || '[]');
const bookings = JSON.parse(localStorage.getItem('site_inspection_bookings') || '[]');

const sitePostcode = '2000';
const sitePostInt = parseInt(sitePostcode, 10);
let nearestBranchId = null;

if (!isNaN(sitePostInt) && branches.length > 0) {
  let best = null;
  branches.forEach(b => {
    if (!b || !b.postcode) return;
    const bp = parseInt(b.postcode, 10);
    if (isNaN(bp)) return;
    const dist = Math.abs(sitePostInt - bp);
    if (!best || dist < best.dist) {
      best = { id: b.id, dist };
    }
  });
  if (best) nearestBranchId = best.id;
}

// Compute target date = 15th of next month relative to current system time
const now = new Date();
let year = now.getFullYear();
let month = now.getMonth(); // 0-based
let targetMonth = month + 1;
if (targetMonth > 11) {
  targetMonth = 0;
  year += 1;
}
const targetDay = 15;

const bookingsForSite = bookings.filter(b => b && b.site_postcode === sitePostcode);
const bookingsWithNearestBranch = bookingsForSite.filter(b => nearestBranchId && b.branch_id === nearestBranchId);
const bookingsWithService = bookingsWithNearestBranch.filter(b => b.service_type === 'retaining_wall_piling');
const bookingsWithCorrectDate = bookingsWithService.filter(b => {
  const d = new Date(b.inspection_date);
  if (isNaN(d.getTime())) return false;
  return d.getFullYear() === year && d.getMonth() === targetMonth && d.getDate() === targetDay;
});

// CP1 (0.5): At least one booking for postcode 2000 uses the nearest branch
checkpoints.push({ passed: bookingsWithNearestBranch.length > 0, weight: 0.5 });

// CP2 (0.5): Among those, at least one is for retaining wall piling on the 15th of next month
checkpoints.push({ passed: bookingsWithCorrectDate.length > 0, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const packages = JSON.parse(localStorage.getItem('earthworks_packages') || '[]');
const packageItems = JSON.parse(localStorage.getItem('earthworks_package_items') || '[]');
const quotes = JSON.parse(localStorage.getItem('quote_requests') || '[]');

// Packages that include excavation, haulage and compaction items, with total hours <= 40 and total cost <= 20000
const qualifyingPackages = packages.filter(pkg => {
  if (!pkg) return false;
  const items = packageItems.filter(it => it.package_id === pkg.id);
  if (items.length === 0) return false;
  const types = new Set(items.map(it => it.item_type));
  const hasExcavation = types.has('excavation');
  const hasHaulage = types.has('haulage_truck_hire');
  const hasCompaction = types.has('compaction_roller_hire');
  if (!hasExcavation || !hasHaulage || !hasCompaction) return false;
  if (typeof pkg.total_machine_hours !== 'number' || pkg.total_machine_hours > 40) return false;
  if (typeof pkg.estimated_total_cost !== 'number' || pkg.estimated_total_cost > 20000) return false;
  return true;
});

// Among those packages, find ones with a linked earthworks_package quote for postcode 4217 mentioning infill
const packagesWithQuote = qualifyingPackages.filter(pkg => {
  return quotes.some(q => {
    if (!q) return false;
    if (q.source_type !== 'earthworks_package') return false;
    if (q.related_earthworks_package_id !== pkg.id) return false;
    if (q.site_postcode !== '4217') return false;
    const desc = (q.project_description || '').toLowerCase();
    return desc.includes('infill');
  });
});

// CP1 (0.4): User created at least one qualifying earthworks package configuration (3 services, <=40 hours, <=$20k)
checkpoints.push({ passed: qualifyingPackages.length > 0, weight: 0.4 });

// CP2 (0.6): User submitted a quote request for postcode 4217 referencing such a package and describing an infill development
checkpoints.push({ passed: packagesWithQuote.length > 0, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
